package com.yasirakbal.order.adapter.out.persistence;

import com.yasirakbal.order.application.domain.model.Order;
import com.yasirakbal.order.application.port.out.OrderItemSnapshot;
import org.mapstruct.Mapper;
import org.mapstruct.Mapping;
import org.mapstruct.Named;

import java.math.BigDecimal;
import java.util.List;

@Mapper(componentModel = "spring")
public interface OrderMapper {

    @Mapping(target = "id", source = "id.value")
    @Mapping(target = "tableId", source = "tableId.value")
    @Mapping(target = "totalAmount", source = "order", qualifiedByName = "calculateTotalAmount")
    @Mapping(target = "items", source = "order", qualifiedByName = "mapItemSnapshots")
    OrderJpaEntity mapToOrderJpaEntity(Order order);

    @Mapping(target = "id", source = "id.value")
    @Mapping(target = "price", source = "price.amount")
    OrderItemJpaEntity mapToOrderItemJpaEntity(OrderItemSnapshot snapshot);

    @Named("calculateTotalAmount")
    default BigDecimal calculateTotalAmount(Order order) {
        return order.calculateTotal().getAmount();
    }

    @Named("mapItemSnapshots")
    default List<OrderItemJpaEntity> mapItemSnapshots(Order order) {
        return order.getItemSnapshots().stream()
                .map(this::mapToOrderItemJpaEntity)
                .toList();
    }
}

package com.yasirakbal.order.adapter.out.persistence;

import com.yasirakbal.order.application.domain.model.Order;
import com.yasirakbal.order.application.domain.model.OrderItem;
import com.yasirakbal.order.application.port.out.OrderItemSnapshot;
import org.mapstruct.Mapper;
import org.mapstruct.Mapping;
import org.mapstruct.Named;

import java.math.BigDecimal;
import java.util.List;

@Mapper(componentModel = "spring")
public interface OrderMapper {

    @Mapping(target = "id", source = "id.value")
    @Mapping(target = "tableId", source = "tableId.value")
    @Mapping(target = "totalAmount", source = "order", qualifiedByName = "calculateTotalAmount")
    @Mapping(target = "items", source = "order", qualifiedByName = "mapItemSnapshots")
    OrderJpaEntity mapToOrderJpaEntity(Order order);

    @Mapping(target = "id", source = "id.value")
    @Mapping(target = "price", source = "price.amount")
    OrderItemJpaEntity mapToOrderItemJpaEntity(OrderItemSnapshot snapshot);

    @Mapping(target = "id", expression = "java(new com.yasirakbal.order.application.domain.model.OrderId(orderJpaEntity.getId()))")
    @Mapping(target = "tableId", expression = "java(new identifier.TableId(orderJpaEntity.getTableId()))")
    @Mapping(target = "items", source = "orderJpaEntity", qualifiedByName = "mapToOrderItems")
    @Mapping(target = "status", source = "orderJpaEntity.status")
    @Mapping(target = "createdAt", source = "orderJpaEntity.createdAt")
    Order mapToOrder(OrderJpaEntity orderJpaEntity);

    @Mapping(target = "id", expression = "java(new com.yasirakbal.order.application.domain.model.OrderItemId(orderItemJpaEntity.getId()))")
    @Mapping(target = "menuItemId", source = "orderItemJpaEntity.menuItemId")
    @Mapping(target = "quantity", source = "orderItemJpaEntity.quantity")
    @Mapping(target = "price", expression = "java(new com.yasirakbal.order.application.domain.model.Money(orderItemJpaEntity.getPrice()))")
    OrderItem mapToOrderItem(OrderItemJpaEntity orderItemJpaEntity);

    @Named("calculateTotalAmount")
    default BigDecimal calculateTotalAmount(Order order) {
        return order.calculateTotal().getAmount();
    }

    @Named("mapItemSnapshots")
    default List<OrderItemJpaEntity> mapItemSnapshots(Order order) {
        return order.getItemSnapshots().stream()
                .map(this::mapToOrderItemJpaEntity)
                .toList();
    }

    @Named("mapToOrderItems")
    default List<OrderItem> mapToOrderItems(OrderJpaEntity orderJpaEntity) {
        return orderJpaEntity.getItems().stream()
                .map(this::mapToOrderItem)
                .toList();
    }
}
